var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"스트레가, 영업 종료합니다~ 내일 다시 봐요~","JPN":"ストレガ、閉店の時間で～す。また明日会いましょう～！","ENG":"Thank you for coming! See you again tomorrow!","TWN":"史特雷加今天就營業到這裡了~明天再見~"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"히, 힘들어...... 집에서도 이렇게 일해 본 적 없는데......","JPN":"つ、疲れた……家でもこんなに働いたことなかったのに……","ENG":"I-I'm exhausted... I've never worked this hard, even at home...","TWN":"好，好累啊……在家裡都沒做過這麼多事情……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"첫날을 무사히 넘기다니 대단한데?","JPN":"初日を無事に終えたなんて、すごいね！","ENG":"You managed to survive day one! I'm impressed.","TWN":"熬過了第一天，蠻厲害的嘛？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"여태까지 찾아온 애들은 다들 하루만에 나가떨어졌거든.","JPN":"今まで来た子たちはみんな一日で辞めちゃったのに。","ENG":"All the other kids dropped out the first day.","TWN":"之前來的人，只做了一天就累跑了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"물론 최강의 마녀가 될 나는 하루도 빠짐없이 근속 중이지만!","JPN":"もちろん、最強の魔女になる私は一日も欠かさず働いてるけど！","ENG":"Of course, I have a perfect attendance record, since I'm going to be greatest witch in the world!","TWN":"當然，要成為最強魔女的我，每一天都在辛勤勞作！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"넌 제발 좀 가라, 가.","JPN":"イングリッドはいい加減帰ってくれ。","ENG":"You of all people are welcome to drop out, Ingrid.","TWN":"好了，妳趕緊走吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그리고 테이블은 다 닦고 딴청 피우는 거야?","JPN":"あと、ちゃんとテーブルを全部拭いたからおしゃべりしてるんだな？","ENG":"And did you finish wiping the tables before you started goofing off?","TWN":"還有桌子都還沒擦呢，還敢偷懶？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"손가락으로 문질러서 먼지 하나 나오면 알바비는 한 푼도 없을 줄 알아.","JPN":"指でこすってほこりが少しでもついたら、バイト代はないと思えよ。","ENG":"I'm going to do a white-gloved inspection. If I see a speck of dust, I'll dock your next paycheck!","TWN":"只要讓我發現一絲的灰塵，妳就別想拿到一分錢！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"아, 안 돼! 나 이번에 인터넷에서 살 거 있단 말이야!","JPN":"だ、ダメ！　ネットで買わなきゃいけないものがあるの！","ENG":"N-no! I've got something to buy online next week!","TWN":"啊，不行！我還要網購呢！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흥. 보나마나 별 시답잖은 물건들이겠지.","JPN":"ふん。どうせくだらないものだろう。","ENG":"Hmpf. It's probably some stupid junk again.","TWN":"哼，不用說肯定是沒用的東西。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"아냐, 이번엔 진짜라고!","JPN":"違う、今回は本当だってば！","ENG":"No! It's legit this time!","TWN":"不，這次才不是呢！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그 유명한 초끈양자 점성술 블로그를 운영하는 마담 클로에 스타시커 알지?","JPN":"あの有名な超紐量子占星術のブログをやってる、マダム・クロエ・スターシーカーは知ってるでしょ？","ENG":"You know Madam Chloe Starseeker? The one running the Superstring Quantum Astrology Blog?","TWN":"妳知道那位經營超玄量子占星術部落格的女老闆克洛伊·尋星吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그 사람이 직접 인증한 신비의 피라미드 파워 고깔모자 3종 세트라구!","JPN":"あの人の認証を受けた、神秘のピラミッドパワーとんがり帽子3種セットなの！","ENG":"They're selling this triple Pyramid Power Cone Hat set she vouched for herself!","TWN":"我要買她親自認證的神秘金字塔能量高帽三件式套裝！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이름만 들어도 전형적인 사이비네, 뭐.","JPN":"名前からして典型的なインチキじゃないか。","ENG":"Sounds like a total fraud.","TWN":"這名字一聽就知道是個典型的邪教。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이 세상에 피라미드 파워 같은 건 없다고 몇 번을 말해?","JPN":"この世にピラミッドパワーなんか無いと何回言えばわかるんだ？","ENG":"How many times do I have to tell you there is no such thing as pyramid power?","TWN":"我跟妳說過多少次，這個世上沒有金字塔能量！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"사이비라니! 그렇지 않아! 마담 스타시커에게 사과해!","JPN":"インチキだなんて！　そんなんじゃない！　マダム・スターシーカーに謝って！","ENG":"She's not a fraud! You owe Madam Starseeker an apology!","TWN":"才不是邪教！妳快跟女老闆尋星道歉！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"야! 머리 잡아당기지 마!","JPN":"おい！　髪を引っ張るな！","ENG":"Hey! Quit pulling on my hair!","TWN":"喂！不要扯我的頭髮！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"할머니...... 대체 절 어디로 보내신 거죠......","JPN":"お婆ちゃん……いったい私をなんてところに送ったの……","ENG":"Grandma... Where have you sent me?","TWN":"奶奶……妳為什麼讓我來到這種地方啊……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아아, 머리 아파. 맘대로 하라지.","JPN":"ううっ、頭が痛い。もう勝手にしろ。","ENG":"Ow, my hair... Fine, suit yourself.","TWN":"唉，真是頭痛。隨妳便吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그보다 신입, 넌 또 왜 주저앉아 있어.","JPN":"それより新入り、なんで座り込んでる？","ENG":"Anyway... Newbie, what are you doing on the floor?","TWN":"新人，妳坐在這裡幹嘛？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아직 얘기 안 끝났으니까 냉큼 일어나.","JPN":"まだ話が終わってないから、早く立て。","ENG":"I'm not done talking yet. Get up.","TWN":"我的話還沒說完呢，趕緊起來。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네, 넵!","JPN":"は、はい！","ENG":"Y-yes, ma'am!","TWN":"是，是！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......메이 할머니의 손녀라고 했지?","JPN":"……メイ婆さんの孫娘だと言ったな？","ENG":"So you're Granny May's granddaughter?","TWN":"妳說妳是梅伊奶奶的孫女……？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그런데요?","JPN":"そ、そうですが……","ENG":"Y-yes.","TWN":"是，是啊？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"할머니는 어떻게 돌아가셨어? 혹시 무슨 사고라도 당하신 거야?","JPN":"お婆ちゃんはどうしてお亡くなりに？　ひょっとして事故にでも？","ENG":"How did she pass away? Was she in some kind of an accident?","TWN":"奶奶是怎麼去世的？是遇到了什麼事故嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아뇨. 그냥 평범하게 노환으로 돌아가셨는데......","JPN":"いえ。普通に老衰で亡くなったんですが……","ENG":"No. She just passed away from old age, like an ordinary old lady...","TWN":"不是，只是歲數大了，然後就去世了……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"돌아가실 때 이 지팡이를 주시면서 여길 찾아가라고 하셨어요.","JPN":"亡くなる前にこの杖を渡されて、ここに行くようにと言われて。","ENG":"Before she passed away, she gave me this staff and told me to seek this place out.","TWN":"去世的時候，她把這個拐杖給了我，然後讓我到這裡來。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저희 가족은 할머니랑 저뿐이라 제가 혼자 남는 걸 많이 걱정하셨거든요.","JPN":"お婆ちゃんと二人暮らしだったので、私が一人になるのをすごく心配してたんです。","ENG":"She was my only family, so she was very worried about me ending up alone.","TWN":"我和奶奶相依為命，奶奶很擔心她走了之後我一個人孤苦無依。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그러니 여기 오면 도와줄 사람이 있을 거라고......","JPN":"ここに来れば助けてくれる人がいるだろうと……","ENG":"She said someone here would help me...","TWN":"所以她就讓我來到這裡，說這裡會有人幫我……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래, 그랬구나......","JPN":"ああ、そうか……","ENG":"I see...","TWN":"嗯，原來如此……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐, 좋아. 잘 왔어.","JPN":"まあ、いいだろう。よく来たよ。","ENG":"Alright. Well, you came to the right place then.","TWN":"好，妳來得好。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그 지팡이에 대해선 얼마나 알고 있어?","JPN":"その杖のことは、どこまで知ってるんだ？","ENG":"How much do you know about that staff, by the way?","TWN":"妳對那個拐杖瞭解有多少？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"으음...... 할머니가 언제나 들고 다니시던 지팡이라는 거 말고는......","JPN":"うーん……お婆ちゃんがいつも持ち歩いていた杖だってこと以外は……","ENG":"Hmm... Well, grandma took it with her everywhere...","TWN":"嗯……我只知道奶奶一直隨身帶著這根拐杖……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"다른 건 잘 모르겠어요. 그냥 평범한 지팡이 아니에요?","JPN":"他にはわからないんです。ただの平凡な杖じゃないんですか？","ENG":"But I don't know much else. Isn't it just an ordinary staff?","TWN":"其他的我就不知道了。這不就是個普通的拐杖嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"메이 할머니가 아무것도 알려주지 않은 모양이구나.","JPN":"メイお婆ちゃんが何も教えてあげなかったみたいね。","ENG":"Granny May didn't tell you anything, did she?","TWN":"看來梅伊奶奶什麼都沒有告訴你啊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그건 지팡이처럼 생겼지만 실은 <color=#ffd34c>워치</color>란다.","JPN":"それはね、杖のような形をしてるけど実は<color=#ffd34c>ウォッチ</color>なのよ。","ENG":"It may look like a staff, but it's actually a <color=#ffd34c>Watch</color>.","TWN":"它雖看起來像個拐杖，但其實是<color=#ffd34c>能量環</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"워치가 뭔지는 알지?","JPN":"ウォッチが何かは知ってるわよね？","ENG":"You know what a Watch is, right?","TWN":"妳知道能量環吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"워치요?","JPN":"ウォッチ？","ENG":"Watch?","TWN":"能量環？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어...... 그러니까 카운터 능력자들이 가지고 다닌다는 시계 말이죠?","JPN":"えっと……カウンター能力者が持ち歩くっていう時計ですよね？","ENG":"Oh... You mean those watches that Counters carry around?","TWN":"額……你說的是制裁者隨身攜帶的錶嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"하지만 이건 전혀 시계처럼 안 생겼는데......?","JPN":"でもこれって、全然時計には見えませんが……","ENG":"But this doesn't look like a watch at all...","TWN":"但是這個一點都不像錶啊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"보통은 그렇지만 워치가 꼭 시계 모양을 하고 있지는 않아.","JPN":"普通はそうなんだけど、ウォッチが時計の形をしているとは限らないの。","ENG":"Well, these Watches don't necessarily look like a timepiece.","TWN":"並不是所有的能量環都是錶的模樣。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"우리 협회의 마녀들이 사용하는 <color=#ffd34c>마도구</color>들은 그런 경향이 더 강하지.","JPN":"うちの協会の魔女たちが使う<color=#ffd34c>魔道具</color>も違う形をしてる物が多いわ。","ENG":"Especially the <color=#ffd34c>magical instruments</color> that the witches in our association use.","TWN":"尤其是我們協會的魔女們使用的<color=#ffd34c>魔導具</color>，就更不像錶。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"메이 할머니의 워치였던 그 지팡이도 마찬가지고.","JPN":"メイお婆ちゃんのウォッチだったその杖も同じ。","ENG":"The same goes for Granny May's Watch... or that staff.","TWN":"梅伊奶奶這個能量環也是如此。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼 저희 할머니가 카운터였다는 말씀이세요? 전 그런 말은 한 번도 못 들었는데......","JPN":"じゃあ、お婆ちゃんはカウンターだったってことですか？　そんな話は聞いたことがないのに……","ENG":"You mean my grandma was a Counter? I never heard anything about that...","TWN":"妳的意思是，我的奶奶也是制裁者？但我從來沒聽奶奶說過啊……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"정확히 말하면 <color=#ffd34c>마녀</color>셨지.","JPN":"正確に言うと、<color=#ffd34c>魔女</color>だったわね。","ENG":"To be precise, she was a <color=#ffd34c>witch</color>.","TWN":"準確地來說，應該是<color=#ffd34c>魔女</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"카운터라고 생각해도 크게 문제될 건 없지만 계통이 다르단다.","JPN":"カウンターだと考えても差し支えないけど、系統が違うの。","ENG":"It's pretty similar to a Counter, I guess... but it's an entirely different breed.","TWN":"妳也可以想成是制裁者，但系統還是不一樣的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼...... 이걸 물려받은 저도 카운터, 아니 마녀가 되는 건가요?","JPN":"それじゃあ……これを譲り受けた私もカウンター、いや魔女になるんですか？","ENG":"So... now that I've inherited this, does that make me a Counter, too? Or a witch?","TWN":"那……我繼承了這個拐杖，那我是不是也能成為制裁者，哦不，魔女呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"일반적으로 워치는 상속되는 물건이 아니야.","JPN":"一般的にウォッチは受け継がれる物じゃないわ。","ENG":"Watches normally don't get bequeathed from one person to next.","TWN":"一般來說能量環是不能繼承的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"보통은 주인이 사망하면 함께 부서지거나, 어디론가 사라지거나 하지.","JPN":"普通は持ち主が死ぬと同時に壊れたり、どこかに消えたりするけれど。","ENG":"They usually break or disappear when the owner dies.","TWN":"隨著主人死亡，能量環會一起破滅或者消失。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하지만 그 지팡이는 주인을 바꿀 수 있는 아주 희귀한 워치들 중의 하나란다.","JPN":"その杖は持ち主を変えられる、とても珍しいウォッチの一つなの。","ENG":"But that staff is one of the very rare Watches capable of switching owners.","TWN":"但那個能量環是可以換主人的非常稀有的能量環之一。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"메이 할머니의 피를 이어받았다면 지팡이의 주인이 되기에 아무 문제 없을 거야.","JPN":"メイお婆ちゃんの血を引くあなたなら、杖の主になるのに何の問題もないはずよ。","ENG":"You shouldn't have any issues becoming its new owner since you inherited Granny May's blood.","TWN":"如果妳繼承了梅伊奶奶的血統，那麼一定可以成為拐杖的主人。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"하지만 이걸 가지고 다닌 지 벌써 며칠이 지났는데......","JPN":"でも、これを持ち歩いて何日も経つのに……","ENG":"But I've been carrying it around for a few days already...","TWN":"我帶著這個拐杖已經有好幾天了……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저한테 특별한 능력 같은 건 안 생겼는걸요.","JPN":"特別な能力みたいなものは生まれてません。","ENG":"I didn't get any special powers or anything.","TWN":"可我身上並沒有出現什麼特殊的能力。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"당연하지. 아까 에블린이 말해 줬잖아.","JPN":"当たり前だ。さっきエヴリンも言っただろ。","ENG":"Of course not. It's like what Evelyn just told you.","TWN":"當然了，剛剛伊芙琳已經說過了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그건 <color=#ffd34c>마법</color>이라는 특별한 술식을 통해서만 구동할 수 있는 <color=#ffd34c>마도구</color>니까.","JPN":"それは<color=#ffd34c>魔法</color>という特別な術式でしか駆動できない<color=#ffd34c>魔道具</color>だからな。","ENG":"The staff is a <color=#ffd34c>magical instrument</color> that can only be activated with specific <color=#ffd34c>magic</color> spells.","TWN":"那個是必須透過<color=#ffd34c>魔法</color>才能驅動的<color=#ffd34c>魔導具</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼 정말 세상에 마법 같은 게 있는 건가요?","JPN":"本当にこの世に魔法があるってことですか？","ENG":"So is there really such a thing as real magic?","TWN":"這個世上真的存在魔法嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"네 입으로 말했잖아? 진짜 마녀 협회를 찾아왔다고.","JPN":"汝もこう言わなかったか？　本物の魔女協会を訪ねてきたと。","ENG":"Well, you're the one who came asking for the real witch association.","TWN":"妳不是說來找真正的魔女公會的嗎。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"마녀가 있는데 마법이 없을 리가 있겠어?","JPN":"魔女がいるのに魔法がないはずないだろ？","ENG":"If witches are real, don't you think magic would have to be real, too?","TWN":"既然有魔女，那怎麼可能沒有魔法？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그건...... 그렇네요.","JPN":"確かに……そうですね。","ENG":"Oh... Yeah, I guess so.","TWN":"這……妳說的沒錯。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"좋아, 그럼 슬슬 <color=#ffd34c>진짜</color> 일을 시작해 볼까?","JPN":"よし、ではそろそろ<color=#ffd34c>本当の</color>仕事を始めてみようか？","ENG":"Alright, time to get to <color=#ffd34c>real</color> work.","TWN":"好，那就開始<color=#ffd34c>真正的</color>工作吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"진짜 일이요? 하지만 손님들은 다들 돌아갔는데?","JPN":"本当の仕事？　お客さんたちはみんな帰りましたよ？","ENG":"Real work? But the customers are all gone now.","TWN":"真正的工作？可現在沒有什麼客人啊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"스트레가 마녀 협회의 본업은 해가 진 뒤에 비로소 시작되는 거야.","JPN":"ストレガ魔女協会の本業は日が暮れてから始まるんだよ。","ENG":"The true work of Strega Witch Association begins after sunset.","TWN":"史特雷加魔女協會的工作是在日落後開始的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"사정상 낮에는 평범한 오컬트 카페로 영업하고 있지만.","JPN":"わけあって昼は平凡なオカルトカフェとして営業しているが。","ENG":"Although by day, we operate as an ordinary occult cafe...","TWN":"白天就只能以靈異咖啡店作掩飾。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"넌 잘 모르겠지만, 메이 할머니는 한 때 우리들 중 최고의 마녀였어.","JPN":"汝はわからないだろうが、メイ婆さんは妾たちの中でも最高の魔女だった。","ENG":"You might not know this, but Granny May used to be the best witch among all of us.","TWN":"妳可能不知道，梅伊奶奶曾經是我們之中最厲害的魔女。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"나를 포함해서 많은 사람들이 그녀의 도움을 받았었지.","JPN":"妾はもちろん、多くの人々が彼女に助けてもらったんだ。","ENG":"She helped a lot of people, including me.","TWN":"包括我在內，很多人都受到過她的幫助。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"만약 네가 할머니의 뒤를 잇고 싶다면 지금부터 날 따라오면 돼.","JPN":"もし汝が後を継ぎたいと思っているなら、妾の言うとおりにすればいい。","ENG":"If you want to succeed your grandmother, you can just do as I say from now on.","TWN":"如果妳想繼承妳奶奶，就好好跟著我吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"베아트릭스의 이름을 걸고 널 진정한 마녀로 만들어 주지.","JPN":"ベアトリクスの名に懸けて、汝を本物の魔女にしてやろう。","ENG":"I pledge by the name of the Beatrix family that I will make you a true witch.","TWN":"我以貝阿朵莉絲的名字發誓，我會讓妳成為真正的魔女。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아. 미리 말해 두는데 쉬운 길은 아닐 거야.","JPN":"あ、先に言っておくが決して簡単な道じゃないぞ。","ENG":"Oh, just a heads up. It won't be easy.","TWN":"對了，提前告訴妳一聲，這個過程並不簡單。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"우린 관리국에 소속된 카운터도 아니고 <color=#ffd34c>마법</color>이라는 형태의, 수상하기 짝이 없는 힘을 추종하니까.","JPN":"妾たちは管理局に所属したカウンターでもない上に<color=#ffd34c>魔法</color>という、極めて怪しい力を扱うからな。","ENG":"We're not Counters associated with the Administration, and we wield a suspicious form of power called <color=#ffd34c>magic</color>.","TWN":"我們不是隸屬於管理局的制裁者，我們崇尚的是極其神秘的<color=#ffd34c>魔法</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그게 싫다면 지금 여길 나가서 다른 사람들처럼 평범하게 살면 돼.","JPN":"それが嫌なら今ここを出て、他の人のように平凡な暮らしをすればいい。","ENG":"If you're not up for that, you're welcome to leave now and lead an ordinary life like everyone else.","TWN":"如果妳不願意，可以現在離開，然後過普通人的生活。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"너무 냉정한 거 아냐, 라우라? 그렇게 쫓아낼 거면 강요나 마찬가지잖아?","JPN":"ラウラ、ちょっと冷たすぎじゃない？　出ていけと言ってるようなもんじゃないの。","ENG":"Aren't you being too harsh, Laura? You're basically telling her to get out if she's not going to join us!","TWN":"蘿拉，妳這樣未免也太無情了吧？妳這不是逼她嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"무슨 소리야? 경제적인 지원은 여길 떠난다고 해도 해 줄 수 있어.","JPN":"何を言ってるんだ？　経済的な支援なら、ここを去ってもしてやれる。","ENG":"What are you talking about? I'm still willing to support her financially even if she leaves.","TWN":"才不是，即使她離開這裡，我也會提供經濟上的援助。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"메이 할머니한테 신세 진 걸 생각하면 햇병아리 하나 돌봐 주는 건 별것 아니니까.","JPN":"メイ婆さんに助けてもらったことを思うと、子ども一人世話することくらい大したことない。","ENG":"Compared to everything we owe Granny May, taking care of this kid is nothing.","TWN":"畢竟受過梅伊奶奶的恩惠，幫她照顧一個小孩子並不是什麼難事。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하지만 진정한 마녀가 되겠다는 건 본인의 각오가 없으면 곤란해.","JPN":"だが、本物の魔女になることは本人の覚悟がないと難しいんだ。","ENG":"But it will take some serious self-determination if she wants to become a true witch.","TWN":"但想要成為魔女，如果本人沒有覺悟是不行的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아무리 메이 할머니의 손녀라고 해도 말이야.","JPN":"いくらメイ婆さんの孫娘だと言ってもな。","ENG":"Even if she's Granny May's granddaughter.","TWN":"即使她是梅伊奶奶的孫女。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"자, 유나 스프링필드. 어떻게 할래?","JPN":"さあ、ユナ・スプリングフィールド。汝はどうしたいんだ？","ENG":"So, Yuna Springfield. What will it be?","TWN":"所以，尤娜，妳的決定是什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"전......","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"전 언제나 할머니에게 받기만 하고 자랐어요.","JPN":"私はいつもお婆ちゃんにもらってばかりでした。","ENG":"I owe everything to my grandma.","TWN":"從小到大是在奶奶的庇護下長大的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저한테 가족은 할머니뿐이었는데......","JPN":"私の家族はお婆ちゃん一人だけだったのに……","ENG":"She was my only family...","TWN":"奶奶是我唯一的家人……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이젠 아무것도 해드릴 수 없게 됐고요.","JPN":"もう何もしてあげられなくなっちゃいました。","ENG":"And now I can't do anything for her in return.","TWN":"但現在，我卻不能為奶奶做點什麼了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"마녀나 마법에 대해선 얘기를 들어도 잘 모르겠어요.","JPN":"魔女とか魔法のことは、聞いてもよくわからないです。","ENG":"All this talk about witches and magic is going straight over my head.","TWN":"無論是魔女還是魔法，我也聽不太懂。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그치만 할머니가 아무 이유 없이 여길 알려 주시진 않았을 거예요.","JPN":"でも、お婆ちゃんがここを教えたことにはきっと理由があるんだと思います。","ENG":"But I'm sure grandma had a very good reason for telling me to come here.","TWN":"但我相信，奶奶讓我來這裡肯定有她的理由。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"만약, 제가 할머니 뒤를 이어 주길 바라셨던 거라면......","JPN":"もし、私が後を継ぐことがお婆ちゃんの願いなら……","ENG":"If what she wanted was for me to follow in her footsteps...","TWN":"如果奶奶是希望我能繼承她……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아무리 힘들어도 그 바람을 꼭 이뤄드리고 싶어요.","JPN":"どれだけ大変でも、その願いを叶えてあげたい。","ENG":"I'd like to do that for her, no matter how challenging it gets.","TWN":"那麼哪怕多難，我也要實現奶奶的夢想。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"좋아. 결정됐네.","JPN":"よし。では決まりだな。","ENG":"Great. That settles it then.","TWN":"好，看來妳下定了決心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그럼 저기 지하실 문 보이지?","JPN":"あそこに地下室の扉が見えるだろ？","ENG":"See that door to the basement there?","TWN":"看到那個地下室的門了嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"어서 저 문으로 들어가.","JPN":"あの扉の中に入るんだ。","ENG":"Go through that door now.","TWN":"開門進去吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 저 엄청 녹슬고 오래된 철문으로요?","JPN":"えっ？　あの錆びついて古そうな鉄の扉ですか？","ENG":"Huh? You mean that really old, rusty metal door?","TWN":"啊？妳是說那個生銹破舊的鐵門嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"뭔가 으스스하고 기분 나빠 보이는데...... 왜 저기로 들어가야 되는데요?","JPN":"なんだか恐ろしくて気味が悪いのに……どうして入らなきゃいけないんですか？","ENG":"It looks creepy... Why do I have to go through there?","TWN":"感覺很陰森啊……為什麼要進去呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뻔하잖아. 이상한 나라의 앨리스도 몰라?","JPN":"どうしても何も。不思議の国のアリスも知らないのか？","ENG":"Isn't it obvious? Haven't you read Alice in Wonderland?","TWN":"知不知道愛麗絲夢遊仙境？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"마법의 세계로 들어가려면 토끼굴로 뛰어들어야 하는 법이지.","JPN":"魔法の世界に入るためには、ウサギの穴に飛び込むしかないだろ。","ENG":"You've got to go down the rabbit hole if you want to enter the world of magic.","TWN":"想要進入魔法世界，當然要通過兔子洞。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};